import 'package:mqtt_client/mqtt_client.dart'; import 'package:mqtt_client/mqtt_server_client.dart'; MqttClient setupMqttClient(String host, String identifier, int port) { final isSecure = host.contains('cloudflare') || port == 443; final protocol = isSecure ? 'wss://' : 'ws://'; final client = MqttServerClient.withPort('$protocol$host', identifier, port); client.useWebSocket = true; if (isSecure) { client.secure = true; } return client; }
